import java.security.SecureRandom

class SessionTokenGenerator {

    private val secureRandom = SecureRandom()
    private val alphanumericChars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    private val tokenLength = 32

    private var currentSessionId: String? = null
    private val activeTokens = mutableMapOf<String, TokenInfo>()

    data class TokenInfo(
        val token: String,
        val sessionId: String,
        val createdAt: Long,
        val expiresAt: Long
    ) {
        fun isExpired(): Boolean = System.currentTimeMillis() > expiresAt
    }

    data class SessionInfo(
        val sessionId: String,
        val createdAt: Long
    )

    private fun generateRandomString(length: Int = tokenLength): String {
        val sb = StringBuilder(length)
        for (i in 0 until length) {
            val index = secureRandom.nextInt(alphanumericChars.length)
            sb.append(alphanumericChars[index])
        }
        return sb.toString()
    }

    fun startSession(): SessionInfo {
        currentSessionId = generateRandomString()
        val createdAt = System.currentTimeMillis()
        cleanupExpiredTokens()
        return SessionInfo(
            sessionId = currentSessionId!!,
            createdAt = createdAt
        )
    }

    fun getCurrentSessionId(): String? = currentSessionId

    fun isSessionActive(): Boolean = currentSessionId != null

    fun generateApiToken(expirationDurationMillis: Long = DEFAULT_TOKEN_EXPIRATION_MILLIS): TokenInfo {
        val sessionId = currentSessionId
            ?: throw IllegalStateException("No active session. Call startSession() first.")

        val token = generateRandomString()
        val now = System.currentTimeMillis()
        val tokenInfo = TokenInfo(
            token = token,
            sessionId = sessionId,
            createdAt = now,
            expiresAt = now + expirationDurationMillis
        )

        activeTokens[token] = tokenInfo
        cleanupExpiredTokens()

        return tokenInfo
    }

    fun validateToken(token: String): Boolean {
        val tokenInfo = activeTokens[token] ?: return false
        if (tokenInfo.isExpired()) {
            activeTokens.remove(token)
            return false
        }
        if (tokenInfo.sessionId != currentSessionId) {
            activeTokens.remove(token)
            return false
        }
        return true
    }

    fun revokeToken(token: String): Boolean {
        return activeTokens.remove(token) != null
    }

    fun getActiveTokenCount(): Int {
        cleanupExpiredTokens()
        return activeTokens.size
    }

    fun getActiveTokens(): List<TokenInfo> {
        cleanupExpiredTokens()
        return activeTokens.values.toList()
    }

    fun endSession() {
        currentSessionId = null
        activeTokens.clear()
    }

    fun refreshSession(): SessionInfo {
        endSession()
        return startSession()
    }

    private fun cleanupExpiredTokens() {
        val expiredKeys = activeTokens.entries
            .filter { it.value.isExpired() }
            .map { it.key }
        expiredKeys.forEach { activeTokens.remove(it) }
    }

    companion object {
        const val DEFAULT_TOKEN_EXPIRATION_MILLIS: Long = 15 * 60 * 1000L // 15 minutes

        @Volatile
        private var instance: SessionTokenGenerator? = null

        fun getInstance(): SessionTokenGenerator {
            return instance ?: synchronized(this) {
                instance ?: SessionTokenGenerator().also { instance = it }
            }
        }
    }
}

class SessionManager {

    private val tokenGenerator = SessionTokenGenerator.getInstance()

    fun onAppOpened(): SessionTokenGenerator.SessionInfo {
        return if (tokenGenerator.isSessionActive()) {
            SessionTokenGenerator.SessionInfo(
                sessionId = tokenGenerator.getCurrentSessionId()!!,
                createdAt = System.currentTimeMillis()
            )
        } else {
            tokenGenerator.startSession()
        }
    }

    fun onAppClosed() {
        tokenGenerator.endSession()
    }

    fun getTokenForApiRequest(
        expirationDurationMillis: Long = SessionTokenGenerator.DEFAULT_TOKEN_EXPIRATION_MILLIS
    ): SessionTokenGenerator.TokenInfo {
        if (!tokenGenerator.isSessionActive()) {
            tokenGenerator.startSession()
        }
        return tokenGenerator.generateApiToken(expirationDurationMillis)
    }

    fun isTokenValid(token: String): Boolean {
        return tokenGenerator.validateToken(token)
    }

    fun invalidateToken(token: String): Boolean {
        return tokenGenerator.revokeToken(token)
    }

    fun refreshCurrentSession(): SessionTokenGenerator.SessionInfo {
        return tokenGenerator.refreshSession()
    }

    fun getSessionStatus(): Map<String, Any?> {
        return mapOf(
            "isActive" to tokenGenerator.isSessionActive(),
            "sessionId" to tokenGenerator.getCurrentSessionId(),
            "activeTokenCount" to tokenGenerator.getActiveTokenCount()
        )
    }
}

